body:
## Steps to reproduce the issue

[clock_gating_post_control.zip](https://github.com/YosysHQ/yosys/files/6035885/clock_gating_post_control.zip)

```
sby -f clock_gating_post_control.sby
gtkwave clock_gating_post_control.gtkw
```
```
`ifdef FORMAL
reg first_clock_had_passed;
initial first_clock_had_passed = 0;
always @(posedge clk) first_clock_had_passed <= 1;

initial assume(clk == 0);

always @($global_clock)
begin
	if(first_clock_had_passed)
		assume(clk == ~$past(clk));
end

always @(posedge clk)
	assume(enable == 0);

localparam MAX_LIMIT = 16;
reg [$clog2(MAX_LIMIT)-1:0] count;
initial count = 0;

always @(posedge clk)
begin
	count <= count + 1;
end

localparam STARTS_FALLING = 4;
localparam STARTS_RISING = 8;

always @(posedge clk)
begin
	// scan_enable signal is asserted low for (STARTS_RISING-STARTS_FALLING-1) clock cycles
	if((count > STARTS_FALLING) && (count < STARTS_RISING))  
		assume(scan_enable == 0);
		
	else
		assume(scan_enable == 1);
end

always @(posedge clk)
begin
	if(first_clock_had_passed)
		cover(~gclk && $past(gclk));
end
`endif

```

## Expected behavior

`count` signal should **ONLY** increment during `posedge clk` , not during `negedge clk`

## Actual behavior

![clk_generation_error](https://user-images.githubusercontent.com/3324659/108999477-5290bf80-76dd-11eb-9d06-b857b35e5418.png)

